class Solution:
    def isPalindrome(self, head: Optional[ListNode]) -> bool:
        if not head or not head.next:
            return True
        # 步骤一：使用快慢指针寻找到链表中间位置
        slow, fast = head, head
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
        # 步骤二：对于链表后半部分进行反转
        def reverseLink(head):
            prev = None
            current = head
            while current:
                next_node = current.next
                current.next = prev
                prev = current
                current = next_node
            return prev
        slow = reverseLink(slow)
        # 步骤三：判断是否为回文链表
        while slow:
            if slow.val != head.val:
                return False
            slow, head = slow.next, head.next
        return True

