class Solution:
    def spiralOrder(self, matrix: List[List[int]]) -> List[int]:
        if not matrix or not matrix[0]:
            return []

        m, n = len(matrix), len(matrix[0])
        top, bottom, left, right = 0, m - 1, 0, n - 1
        result = []

        while top <= bottom and left <= right:
            # 从左到右遍历顶部行
            for i in range(left, right + 1):
                result.append(matrix[top][i])
            top += 1  # 顶部行已遍历，下移一行

            # 从上到下遍历右侧列
            for i in range(top, bottom + 1):
                result.append(matrix[i][right])
            right -= 1  # 右侧列已遍历，左移一列

            # 检查是否还有剩余的行和列
            if top <= bottom:
                # 从右到左遍历底部行
                for i in range(right, left - 1, -1):
                    result.append(matrix[bottom][i])
                bottom -= 1  # 底部行已遍历，上移一行

            if left <= right:
                # 从下到上遍历左侧列
                for i in range(bottom, top - 1, -1):
                    result.append(matrix[i][left])
                left += 1  # 左侧列已遍历，右移一列

        return result

class Solution:
    def searchMatrix(self, matrix: List[List[int]], target: int) -> bool:
        # 获取矩阵的行数和列数
        if not matrix or not matrix[0]:
            return False
        rows, cols = len(matrix), len(matrix[0])

        # 从右上角开始
        row, col = 0, cols - 1

        while row < rows and col >= 0:
            if matrix[row][col] == target:
                return True
            elif matrix[row][col] > target:
                # 如果当前元素比目标大，向左移动
                col -= 1
            else:
                # 如果当前元素比目标小，向下移动
                row += 1

        return False

class Solution:
    def detectCycle(self, head: Optional[ListNode]) -> Optional[ListNode]:
        if not head or not head.next:
            return None

        slow = head
        fast = head

        # 检测是否有环
        while fast and fast.next:
            slow = slow.next
            fast = fast.next.next
            if slow == fast:
                break
        else:
            return None

        # 找到环的起始节点
        slow = head
        while slow != fast:
            slow = slow.next
            fast = fast.next

        return slow

class Solution:
    def sortList(self, head: Optional[ListNode]) -> Optional[ListNode]:
        if not head or not head.next:
            return head

        # 找到链表的中间节点
        def find_mid(head: ListNode) -> ListNode:
            slow, fast = head, head.next
            while fast and fast.next:
                slow = slow.next
                fast = fast.next.next
            return slow

        # 合并两个有序链表
        def merge(l1: ListNode, l2: ListNode) -> ListNode:
            dummy = ListNode()
            current = dummy
            while l1 and l2:
                if l1.val < l2.val:
                    current.next = l1
                    l1 = l1.next
                else:
                    current.next = l2
                    l2 = l2.next
                current = current.next
            if l1:
                current.next = l1
            if l2:
                current.next = l2
            return dummy.next

        # 找到中间节点并分割链表
        mid = find_mid(head)
        right = mid.next
        mid.next = None
        left = head

        # 递归排序
        left = self.sortList(left)
        right = self.sortList(right)

        # 合并排序后的子链表
        return merge(left, right)

class Solution:
    def levelOrder(self, root: Optional[TreeNode]) -> List[List[int]]:
        if not root:
            return []  # 如果根节点为空，直接返回空列表

        result = []  # 用于存储最终的层序遍历结果
        queue = deque([root])  # 初始化队列，将根节点加入队列

        while queue:
            level_size = len(queue)  # 记录当前层的节点数
            current_level = []  # 用于存储当前层的节点值

            for _ in range(level_size):
                node = queue.popleft()  # 从队列中取出一个节点
                current_level.append(node.val)  # 将节点值加入当前层的列表

                if node.left:
                    queue.append(node.left)  # 如果节点有左子节点，将左子节点加入队列
                if node.right:
                    queue.append(node.right)  # 如果节点有右子节点，将右子节点加入队列

            result.append(current_level)  # 将当前层的节点值列表加入结果列表

        return result  # 返回最终的层序遍历结果

class Solution:
	def isValidBST(root: TreeNode) -> bool:
	    def helper(node, min_val=float('-inf'), max_val=float('inf')):
	        # 如果当前节点为空，返回 True，因为空树是有效的BST
	        if not node:
	            return True

	        # 检查当前节点的值是否在指定的范围内
	        if not (min_val < node.val < max_val):
	            return False

	        # 递归检查左子树
	        # 左子树的所有节点值必须小于当前节点的值
	        left_valid = helper(node.left, min_val, node.val)

	        # 递归检查右子树
	        # 右子树的所有节点值必须大于当前节点的值
	        right_valid = helper(node.right, node.val, max_val)

	        # 只有当左右子树都满足条件时，当前节点才是有效的BST
	        return left_valid and right_valid

	    # 初始调用，范围是负无穷到正无穷
	    return helper(root)

class Solution:
    def rightSideView(self, root: Optional[TreeNode]) -> List[int]:
        if not root:
            return []  # 如果根节点为空，返回空列表

        result = []  # 用于存储从右侧看到的节点值
        queue = deque([root])  # 初始化队列，将根节点加入队列

        while queue:
            # 当前层的节点数
            level_length = len(queue)

            for i in range(level_length):
                # 从队列中取出一个节点
                node = queue.popleft()

                # 如果是当前层的最后一个节点，将其值加入结果列表
                if i == level_length - 1:
                    result.append(node.val)

                # 将当前节点的子节点加入队列
                if node.left:
                    queue.append(node.left)
                if node.right:
                    queue.append(node.right)

        return result  # 返回从右侧看到的节点值

class Solution:
    def orangesRotting(self, grid: List[List[int]]) -> int:
        if not grid:
            return -1

        rows, cols = len(grid), len(grid[0])
        fresh_count = 0
        queue = deque()

        # 初始化队列和新鲜橘子计数
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 2:
                    queue.append((r, c))  # 将所有初始腐烂的橘子加入队列
                elif grid[r][c] == 1:
                    fresh_count += 1  # 统计新鲜橘子的数量

        # 定义四个方向：上下左右
        directions = [(1, 0), (-1, 0), (0, 1), (0, -1)]
        minutes_passed = 0  # 记录时间

        # 广度优先搜索
        while queue and fresh_count > 0:
            minutes_passed += 1  # 每处理完一轮，时间增加1分钟
            for _ in range(len(queue)):
                r, c = queue.popleft()  # 从队列中取出一个腐烂的橘子
                for dr, dc in directions:
                    nr, nc = r + dr, c + dc  # 计算相邻的单元格位置
                    if 0 <= nr < rows and 0 <= nc < cols and grid[nr][nc] == 1:
                        # 如果相邻单元格是新鲜橘子，将其变为腐烂橘子
                        grid[nr][nc] = 2
                        fresh_count -= 1  # 新鲜橘子数量减少1
                        queue.append((nr, nc))  # 将新腐烂的橘子加入队列

        # 检查是否还有新鲜橘子
        if fresh_count == 0:
            return minutes_passed  # 如果没有新鲜橘子，返回经过的分钟数
        else:
            return -1  # 如果还有新鲜橘子，返回-1

class Trie:
    def __init__(self):
        # 初始化一个空的字典树根节点，根节点本身也是一个字典
        self.root = {}

    def insert(self, word: str) -> None:
        # 从根节点开始逐个插入字符
        node = self.root
        for char in word:
            # 如果当前字符不在当前节点中，添加这个字符
            if char not in node:
                node[char] = {}
            node = node[char]
        # 插入完成后，在末尾标记此位置为单词结束
        node['#'] = True  # '#' 是结束标记符，表示这个路径为一个完整单词

    def search(self, word: str) -> bool:
        # 从根节点开始搜索字符
        node = self.root
        for char in word:
            # 如果字符不在节点中，则表示字典树中不存在该单词
            if char not in node:
                return False
            node = node[char]
        # 判断最后的节点是否有单词结束标记
        return '#' in node

    def startsWith(self, prefix: str) -> bool:
        # 从根节点开始逐个字符检查前缀
        node = self.root
        for char in prefix:
            # 如果前缀中的字符不在字典树中，返回 False
            if char not in node:
                return False
            node = node[char]
        # 如果可以走完前缀，说明存在该前缀
        return True

