            if start == len(s):
                result.append(path[:])
                return

            # 尝试从 start 开始的每一个位置分割字符串
            for end in range(start + 1, len(s) + 1):
                # 获取当前子串 s[start:end]
                substring = s[start:end]

                # 如果当前子串是回文，继续递归处理剩余部分
                if is_palindrome(substring):
                    path.append(substring)  # 选择当前子串
                    backtrack(end, path)    # 递归处理剩余部分
                    path.pop()              # 回溯，撤销选择

        result = []
        backtrack(0, [])
        return result

class Solution:
    def searchMatrix(self, matrix: List[List[int]], target: int) -> bool:
        # 获取矩阵的行数和列数
        if not matrix or not matrix[0]:
            return False
        rows, cols = len(matrix), len(matrix[0])

        # 从右上角开始
        row, col = 0, cols - 1

        while row < rows and col >= 0:
            if matrix[row][col] == target:
                return True
            elif matrix[row][col] > target:
                # 如果当前元素比目标大，向左移动
                col -= 1
            else:
                # 如果当前元素比目标小，向下移动
                row += 1

        return False

class Solution:
    def searchRange(nums, target):
        def binary_search(nums, target, find_first):
            left, right = 0, len(nums) - 1
            result = -1
            while left <= right:
                mid = (left + right) // 2
                if nums[mid] == target:
                    result = mid
                    if find_first:
                        right = mid - 1  # 寻找左边界
                    else:
                        left = mid + 1   # 寻找右边界
                elif nums[mid] < target:
                    left = mid + 1
                else:
                    right = mid - 1
            return result

        start = binary_search(nums, target, True)
        end = binary_search(nums, target, False)

        return [start, end] if start != -1 else [-1, -1]

class Solution:
    def search(self, nums: List[int], target: int) -> int:
        left, right = 0, len(nums) - 1

        while left <= right:
            mid = (left + right) // 2

            # 如果找到目标值，直接返回
            if nums[mid] == target:
                return mid

            # 判断左半部分是否有序
            if nums[left] <= nums[mid]:
                # 如果目标值在左半部分的有序区间中
                if nums[left] <= target < nums[mid]:
                    right = mid - 1  # 缩小右边界，继续在左半部分查找
                else:
                    left = mid + 1   # 否则，目标值可能在右半部分
            # 否则右半部分有序
            else:
                # 如果目标值在右半部分的有序区间中
                if nums[mid] < target <= nums[right]:
                    left = mid + 1   # 缩小左边界，继续在右半部分查找
                else:
                    right = mid - 1  # 否则，目标值可能在左半部分

        return -1

class Solution:
    def findMin(self, nums: List[int]) -> int:
        left, right = 0, len(nums) - 1

        while left < right:
            mid = (left + right) // 2

            # 如果中间值大于最右边的值，说明最小值在右半部分
            if nums[mid] > nums[right]:
                left = mid + 1
            # 否则，最小值在左半部分（包括 mid 自己）
            else:
                right = mid

        # 当 left == right 时，找到了最小值
        return nums[left]

class MinStack:

    def __init__(self):
        self.stack = []
        self.min_stack = []

    def push(self, val: int) -> None:
        self.stack.append(val)
        if not self.min_stack or val <= self.min_stack[-1]:
            self.min_stack.append(val)

    def pop(self) -> None:
        val = self.stack.pop()
        if val == self.min_stack[-1]:
            self.min_stack.pop()

    def top(self) -> int:
        return self.stack[-1]

    def getMin(self) -> int:
        return self.min_stack[-1]

class Solution:
    def findKthLargest(self, nums: list[int], k: int) -> int:
        # 使用大小为 k 的最小堆
        min_heap = []

        for num in nums:
            heapq.heappush(min_heap, num)
            # 如果堆的大小超过 k，弹出堆顶最小值
            if len(min_heap) > k:
                heapq.heappop(min_heap)

        # 堆顶即为第 k 大的元素
        return min_heap[0]

class Solution:
    def canJump(self, nums: List[int]) -> bool:
        max_reachable = 0
        for i in range(len(nums)):
            if i > max_reachable:
                return False
            max_reachable = max(max_reachable, i + nums[i])
        return True

class Solution:
    def coinChange(self, coins: List[int], amount: int) -> int:
        # 初始化dp数组，dp[i]表示凑成i元最少需要的硬币数量
        dp = [float('inf')] * (amount + 1)
        dp[0] = 0  # 凑成0元需要0个硬币

        # 从1元开始，逐步计算每个金额的最优解
        for i in range(1, amount + 1):
            # 遍历所有硬币面额
            for coin in coins:
                if i - coin >= 0:  # 如果当前硬币可以用来凑成i
                    dp[i] = min(dp[i], dp[i - coin] + 1)

        # 如果dp[amount]仍然是无穷大，说明无法凑成该金额
        return dp[amount] if dp[amount] != float('inf') else -1

class Solution:
    def lengthOfLIS(self, nums: List[int]) -> int:
        # tails 数组记录每个长度的递增子序列的最小结尾值
        tails = []

        # 手动实现二分查找，用于找到 tails 中第一个大于等于 target 的位置
        def binary_search(tails, target):
            left, right = 0, len(tails) - 1
            while left <= right:
                mid = left + (right - left) // 2
                if tails[mid] < target:
                    left = mid + 1
                else:
                    right = mid - 1
            return left

        for num in nums:
            # 找到 tails 中第一个大于等于 num 的位置
            idx = binary_search(tails, num)

            # 如果没有找到合适的位置，说明 num 大于 tails 中的所有元素
            if idx == len(tails):
                tails.append(num)
            else:
                # 用 num 替换掉 tails[idx]，使得结尾元素尽可能小
                tails[idx] = num

        # 最终 tails 数组的长度就是最长递增子序列的长度
        return len(tails)

class Solution:
    def minPathSum(self, grid: List[List[int]]) -> int:
        m = len(grid)
        n = len(grid[0])

        # 创建一个二维数组 dp，用于存储到达每个点的最小路径和
        dp = [[0] * n for _ in range(m)]

        dp[0][0] = grid[0][0]

        # 填充第一行（只能从左边移动）
        for j in range(1, n):
            dp[0][j] = dp[0][j - 1] + grid[0][j]

        # 填充第一列（只能从上面移动）
        for i in range(1, m):
            dp[i][0] = dp[i - 1][0] + grid[i][0]

        # 填充剩余的 dp 数组
        for i in range(1, m):
            for j in range(1, n):
                # 当前点的最小路径和 = 当前点的值 + 上方和左方的最小路径和
                dp[i][j] = grid[i][j] + min(dp[i - 1][j], dp[i][j - 1])

        return dp[m - 1][n - 1]

class Solution:
    def longestCommonSubsequence(self, text1: str, text2: str) -> int:
        # 获取两个字符串的长度
        m, n = len(text1), len(text2)

        # 初始化 DP 表，dp[i][j] 表示 text1[0:i] 和 text2[0:j] 的最长公共子序列长度
        dp = [[0] * (n + 1) for _ in range(m + 1)]

        # 填充 DP 表
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if text1[i - 1] == text2[j - 1]:
                    # 当前字符相同，公共子序列长度加1
                    dp[i][j] = dp[i - 1][j - 1] + 1
                else:
                    # 当前字符不相同，取两个可能情况的最大值
                    dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

        # 返回最终的最长公共子序列长度
        return dp[m][n]

class Solution:
    def minDistance(self, word1: str, word2: str) -> int:
        m, n = len(word1), len(word2)
        dp = [[0] * (n + 1) for _ in range(m + 1)]

        for i in range(1, m + 1):
            dp[i][0] = i  # 从 word1[0:i] 变成空字符串，执行 i 次删除操作
        for j in range(1, n + 1):
            dp[0][j] = j  # 从空字符串变成 word2[0:j]，执行 j 次插入操作

        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if word1[i - 1] == word2[j - 1]:
                    dp[i][j] = dp[i - 1][j - 1]
                else:
                    # 如果不同，取插入、删除、替换操作的最小值，并加1表示一次操作
                    dp[i][j] = min(dp[i - 1][j] + 1,    # 删除
                                   dp[i][j - 1] + 1,    # 插入
                                   dp[i - 1][j - 1] + 1)  # 替换

        # 返回最终的最少操作次数
        return dp[m][n]

class Solution:
    def sortColors(self, nums: List[int]) -> None:
        low, mid, high = 0, 0, len(nums) - 1

        while mid <= high:
            if nums[mid] == 0:
                nums[low], nums[mid] = nums[mid], nums[low]
                low += 1
                mid += 1
            elif nums[mid] == 1:
                mid += 1
            else:  # nums[mid] == 2
                nums[mid], nums[high] = nums[high], nums[mid]
                high -= 1
